function executeSkill(context) {
  const sourcePiece = context.piece;
  const targetAlly = selectTarget({ type: 'piece', range: 10, filter: 'ally' });
  if (!targetAlly || targetAlly.needsTargetSelection) {
    return targetAlly;
  }
  targetAlly.attack += 2;
  const damageResult = dealDamage(sourcePiece, targetAlly, 4, 'magical', context.battle, context.skill.id);
  return {
    message: sourcePiece.name + '使用邪能赐福，' + targetAlly.name + '获得2点攻击力并受到' + damageResult.damage + '点伤害',
    success: true
  };
}

